///
/// - `Ok(Vec<String>)` - Vector of post-processor names
/// - `Err(...)` if the registry lock is poisoned
pub fn list_post_processors() -> Result<Vec<String>, String> {
    kreuzberg::list_post_processors()
        .map(|v| v.into_iter().map(|s| s.to_string()).collect::<Vec<_>>())
        .map_err(|e| e.to_string())
}

/// List names of all registered renderers.
///
/// **Errors:**
///
/// Returns an error if the registry lock is poisoned.
pub fn list_renderers() -> Result<Vec<String>, String> {
    kreuzberg::list_renderers()
        .map(|v| v.into_iter().map(|s| s.to_string()).collect::<Vec<_>>())
        .map_err(|e| e.to_string())
}

/// List names of all registered validators.
pub fn list_validators() -> Result<Vec<String>, String> {
    kreuzberg::list_validators()
        .map(|v| v.into_iter().map(|s| s.to_string()).collect::<Vec<_>>())
        .map_err(|e| e.to_string())
}

/// Generate embeddings asynchronously for a list of text strings.
///
/// This is the async counterpart to `embed_texts`. It offloads the blocking
/// ONNX inference work to a dedicated blocking thread pool via Tokio's
/// `spawn_blocking`, keeping the async executor free.
///
/// Returns one embedding vector per input text in the same order.
///
/// **Errors:**
///
/// - `KreuzbergError.MissingDependency` if ONNX Runtime is not installed
/// - `KreuzbergError.Embedding` if the preset name is unknown, model download fails,
///   or the blocking inference task panics
pub async fn embed_texts_async(texts: Vec<String>, config: EmbeddingConfig) -> Result<Vec<Vec<f64>>, String> {
    kreuzberg::embed_texts_async(texts, &kreuzberg::EmbeddingConfig::from(config))
        .await
        .map(|v| {
            v.into_iter()
                .map(|row| row.into_iter().map(|x| x as f64).collect::<Vec<_>>())
                .collect::<Vec<_>>()
        })
        .map_err(|e| e.to_string())
}

/// Render a single PDF page to PNG bytes.
///
/// Returns raw PNG-encoded bytes for the specified page at the given DPI.
/// Uses pdf_oxide with tiny-skia for pure-Rust rendering.
///
/// **Errors:**
///
/// Returns `KreuzbergError.Parsing` if the PDF cannot be opened, authenticated,
/// or rendered, or if `page_index` is out of range.
pub fn render_pdf_page_to_png(
    pdf_bytes: Vec<u8>,
    page_index: i64,
    dpi: Option<i64>,
    password: Option<String>,
) -> Result<Vec<u8>, String> {
    kreuzberg::render_pdf_page_to_png(
        &pdf_bytes,
        page_index as usize,
        dpi.map(|v| v as i32),
        password.as_deref(),
    )
    .map(|v| v)
    .map_err(|e| e.to_string())
}

/// Detect the MIME type of a file at the given path.
///
/// Uses the file extension and optionally the file content to determine the MIME type.
/// Set `check_exists` to `true` to verify the file exists before detection.
pub fn detect_mime_type(path: String, check_exists: bool) -> Result<String, String> {
    kreuzberg::detect_mime_type(path, check_exists)
        .map(|v| v.to_string())
        .map_err(|e| e.to_string())
}

/// Embed a list of texts using the configured embedding model.
///
/// Returns a 2D vector where each inner vector is the embedding for the corresponding text.
pub fn embed_texts(texts: Vec<String>, config: EmbeddingConfig) -> Result<Vec<Vec<f64>>, String> {
    kreuzberg::embed_texts(texts, &kreuzberg::EmbeddingConfig::from(config))
        .map(|v| {
            v.into_iter()
                .map(|row| row.into_iter().map(|x| x as f64).collect::<Vec<_>>())
                .collect::<Vec<_>>()
        })
        .map_err(|e| e.to_string())
}

/// Get an embedding preset by name.
///
/// Returns `null` if no preset with the given name exists. Returns an owned
/// clone so the value is safe to pass across FFI boundaries.
pub fn get_embedding_preset(name: String) -> Option<EmbeddingPreset> {
    (|v: Option<_>| v.map(EmbeddingPreset::from))(kreuzberg::get_embedding_preset(&name))
}

/// List the names of all available embedding presets.
///
/// Returns owned `String`s so the values are safe to pass across FFI boundaries.
pub fn list_embedding_presets() -> Vec<String> {
    kreuzberg::list_embedding_presets()
        .into_iter()
        .map(|s| s.to_string())
        .collect::<Vec<_>>()
}

